// WAHA posts every event here. Keep only inbound text messages.
const b = $input.first().json.body || $input.first().json;
if (b.event !== 'message') return [];
const p = b.payload || {};
if (p.fromMe) return [];
const text = (p.body || '').trim();
if (!text) return [];

// Owner allow-list: only this number may drive SOFI. Set your number in the
// N8N env as SOFI_OWNER_CHAT (e.g. 963XXXXXXXXX@c.us). Empty = allow all (dev).
const owner = ($env.SOFI_OWNER_CHAT || '').trim();
if (owner && p.from !== owner) return [];

return [{ json: {
  chatId: p.from,
  session: b.session || 'default',
  text,
  messageId: p.id || ''
} }];

// Map the WhatsApp text into a SOFI dispatch.
// Convention: first word may be a command keyword; otherwise treat whole text
// as a natural-language instruction for the CEO to route.
const text = $json.text;
const [w0, ...rest] = text.split(/\s+/);
const kw = w0.toLowerCase();
const arg = rest.join(' ').trim();

const project = 'PRJ-SAKK';
let role = 'sofi-ceo';
let command = text;
let model = 'haiku';

const map = {
  audit:   ['sofi-qa-sre-lead',   `Run an audit pass on ${project} (${arg || 'all layers'}). Report findings ranked by severity.`],
  fix:     ['sofi-ceo',           `Fix in ${project}: ${arg}. Route to the cheapest specialist, checkpoint each change.`],
  report:  ['sofi-ceo',           `Produce a ${arg || 'status'} report for ${project}.`],
  feature: ['sofi-ceo',           `Run the full feature loop on ${project}: ${arg}`],
  gate:    ['sofi-ceo',           `Report the current gate + blockers for ${project}.`],
  status:  ['sofi-ceo',           `Give a short status of ${project}: gate, last work, open tickets.`],
  sync:    ['sofi-ceo',           `sofi sync ${project} and summarize what changed.`]
};

if (map[kw]) { [role, command] = map[kw]; }
if (kw === 'feature' || kw === 'fix') { model = 'sonnet'; }

const base = $env.SOFI_CALLBACK_BASE || 'http://127.0.0.1:5678';
return [{ json: {
  role, project, command, model,
  mode: 'async',
  source: 'whatsapp',
  callback_url: `${base}/webhook/sofi-callback`,
  meta: { chatId: $json.chatId, session: $json.session }
} }];
